     5→  DatasetComponentOption,
     6→  DataZoomComponentOption,
     7→  GeoComponentOption,
     8→  GraphicComponentOption,
     9→  LegendComponentOption,
    10→  MarkAreaComponentOption,
    11→  MarkLineComponentOption,
    12→  MarkPointComponentOption,
    13→  MatrixComponentOption,
    14→  PolarComponentOption,
    15→  SingleAxisComponentOption,
    16→  TimelineComponentOption,
    17→  TitleComponentOption,
    18→  ToolboxComponentOption,
    19→  TooltipComponentOption,
    20→  VisualMapComponentOption,
    21→} from 'echarts';
    22→import {
    23→  BrushComponent,
    24→  CalendarComponent,
    25→  DatasetComponent,
    26→  DataZoomComponent,
    27→  GeoComponent,
    28→  GraphicComponent,
    29→  LegendComponent,
    30→  MarkAreaComponent,
    31→  MarkLineComponent,
    32→  MarkPointComponent,
    33→  MatrixComponent,
    34→  PolarComponent,
    35→  SingleAxisComponent,
    36→  TimelineComponent,
    37→  TitleComponent,
    38→  ToolboxComponent,
    39→  TooltipComponent,
    40→  TransformComponent,
    41→  VisualMapComponent,
    42→} from 'echarts/components';
    43→import type { ComponentOption } from 'echarts/types/src/util/types.js';
    44→import React from 'react';
    45→import { useChartContext, useRegister, type EChartExt } from './shared.js';
    46→
    47→function defineComponent<T extends ComponentOption>(ext: EChartExt) {
    48→  return function ChartComponent(props: ComposeOption<T>) {
    49→    const ctx = useChartContext();
    50→
    51→    useRegister((echarts) => {
    52→      echarts.use(ext);
    53→    });
    54→
    55→    React.useLayoutEffect(() => {
    56→      ctx.options.push(props);
    57→    });
    58→
    59→    return null;
    60→  };
    61→}
    62→
    63→export const Brush = /*#__PURE__*/ defineComponent<BrushComponentOption>([BrushComponent]);
    64→
    65→export const Calendar = /*#__PURE__*/ defineComponent<CalendarComponentOption>([CalendarComponent]);
    66→
    67→export const Dataset = /*#__PURE__*/ defineComponent<DatasetComponentOption>([DatasetComponent, TransformComponent]);
