    69→export const DataZoom = /*#__PURE__*/ defineComponent<DataZoomComponentOption>([DataZoomComponent]);
    70→
    71→export const Geo = /*#__PURE__*/ defineComponent<GeoComponentOption>([GeoComponent]);
    72→
    73→export const Graphic = /*#__PURE__*/ defineComponent<GraphicComponentOption>([GraphicComponent]);
    74→
